-- Sessie 6 — beroep-autofill (idempotent): functietitel = beroepsnaam; ontbrekende aangemaakt + gekoppeld.
UPDATE speakers SET beroep_id=(SELECT b.id FROM beroepen b WHERE lower(trim(b.name))=lower(trim(job_title)) ORDER BY b.id LIMIT 1) WHERE beroep_id IS NULL AND job_title IS NOT NULL AND job_title<>'';
